import { initializeApp, getApps } from "firebase/app";
import { getFirestore } from "firebase/firestore";
import { getAuth } from "firebase/auth";
import { getFunctions } from "firebase/functions"; // Import getFunctions

const firebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID
};

const stagingFirebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY_STAGING,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN_STAGING,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID_STAGING,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET_STAGING,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID_STAGING,
  appId: import.meta.env.VITE_FIREBASE_APP_ID_STAGING
};

// Validate required config
const requiredFields = ['apiKey', 'authDomain', 'projectId'];
const missingFields = requiredFields.filter(field => !firebaseConfig[field]);

if (missingFields.length > 0) {
  console.error('Firebase configuration is incomplete. Missing fields:', missingFields);
  console.error('Available env vars:', Object.keys(import.meta.env).filter(key => key.startsWith('VITE_FIREBASE_')));
  throw new Error(`Firebase configuration incomplete. Missing: ${missingFields.join(', ')}`);
}

// Singleton pattern for default app
const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApps()[0];

// Initialize a separate app for staging functions, if different from default
let stagingApp = app;
if (stagingFirebaseConfig.projectId && stagingFirebaseConfig.projectId !== firebaseConfig.projectId) {
  if (!getApps().some(app => app.name === 'stagingFunctionsApp')) {
    stagingApp = initializeApp(stagingFirebaseConfig, 'stagingFunctionsApp');
  } else {
    stagingApp = getApps().find(app => app.name === 'stagingFunctionsApp');
  }
}

export const db = getFirestore(app);
export const auth = getAuth(app);
export const functionsInstance = getFunctions(app); // Default functions instance
export const stagingFunctionsInstance = getFunctions(stagingApp); // Staging functions instance

export default app;

